from lxml import etree

def process_soap_xml(xml_string):
    """
    Processes SOAP XML requests and extracts the message body.

    Args:
        xml_string: The SOAP XML request string.

    Returns:
        The SOAP message body as a string.
    """

    # Parse the SOAP XML with DTD validation
    parser = etree.XMLParser(dtd_validation=True)
    root = etree.fromstring(xml_string.encode('utf-8'), parser=parser)

    # Extract the SOAP body
    soap_body = root.find('soapenv:Body', namespaces={'soapenv': 'soapenv'})

    # Return the SOAP message body as a string
    return etree.tostring(soap_body, encoding='utf-8').decode('utf-8')